// Build a constrained learning prompt from editorial feedback.
const input = $input.first().json;
const body = input.body ?? input;

if (!body.feedbackId || !body.editorialDiff) {
  throw new Error('feedbackId and editorialDiff are required');
}

const systemPrompt = `你是 Phoenix AI Content Engine 的 Writing Memory 分析員。你的任務不是改寫文章，而是從人工修改紀錄中抽取可重複使用的寫作偏好。

規則：
1. 只根據提供的差異推論，不要猜測作者未表達的偏好。
2. 將偏好分成 opening、title、paragraph、tone、transition、cta、avoidPhrases、generalRules。
3. 每一條規則必須簡短、可操作、可放進未來 Writer Prompt。
4. 對每一條規則提供 confidence，範圍 0 到 1。
5. 若只有單篇證據，confidence 不得高於 0.65。
6. 僅輸出合法 JSON，不要使用 Markdown code fence。

輸出格式：
{
  "profileVersion": "1.0.0",
  "rules": [
    {
      "category": "opening|title|paragraph|tone|transition|cta|avoidPhrases|generalRules",
      "rule": "可操作規則",
      "evidence": ["差異證據"],
      "confidence": 0.0
    }
  ],
  "avoidPhrases": ["應避免的詞句"],
  "preferredPatterns": ["偏好的模式"],
  "summary": "本次學習摘要"
}`;

const userPrompt = JSON.stringify({
  feedbackId: body.feedbackId,
  originalDraft: body.originalDraft,
  finalVersion: body.finalVersion,
  editorialDiff: body.editorialDiff,
  metrics: body.metrics
});

return [{
  json: {
    original: body,
    systemPrompt,
    userPrompt
  }
}];

