// Parse and validate the primary learning response.
const response = $input.first().json;
const original = $('BuildLearningPrompt').first().json.original;
const statusCode = response.statusCode ?? 0;
const raw = response.body?.choices?.[0]?.message?.content ?? '';

let memory = null;
let parseError = null;

try {
  memory = JSON.parse(String(raw).replace(/^```json\s*|\s*```$/g, '').trim());
} catch (error) {
  parseError = error.message;
}

const valid = statusCode >= 200 &&
  statusCode < 300 &&
  memory &&
  Array.isArray(memory.rules) &&
  typeof memory.summary === 'string';

return [{
  json: {
    original,
    provider: 'openrouter',
    statusCode,
    raw,
    memory,
    valid,
    fallbackRequired: !valid,
    error: parseError
  }
}];

