// Parse and validate the NVIDIA fallback learning response.
const response = $input.first().json;
const original = $('BuildLearningPrompt').first().json.original;
const statusCode = response.statusCode ?? 0;
const raw = response.body?.choices?.[0]?.message?.content ?? '';

let memory;
try {
  memory = JSON.parse(String(raw).replace(/^```json\s*|\s*```$/g, '').trim());
} catch (error) {
  throw new Error(`NVIDIA learning response is not valid JSON: ${error.message}`);
}

if (!(statusCode >= 200 && statusCode < 300)) {
  throw new Error(`NVIDIA learning request failed with status ${statusCode}`);
}

if (!Array.isArray(memory.rules) || typeof memory.summary !== 'string') {
  throw new Error('NVIDIA learning response does not satisfy the memory contract');
}

return [{
  json: {
    original,
    provider: 'nvidia',
    memory
  }
}];

// Normalize learned writing rules into a stable memory contract.
const input = $input.first().json;
const original = input.original;
const memory = input.memory ?? {};

const allowedCategories = new Set([
  'opening',
  'title',
  'paragraph',
  'tone',
  'transition',
  'cta',
  'avoidPhrases',
  'generalRules'
]);

const rules = (Array.isArray(memory.rules) ? memory.rules : [])
  .map((rule) => ({
    category: allowedCategories.has(rule.category) ? rule.category : 'generalRules',
    rule: String(rule.rule ?? '').trim(),
    evidence: Array.isArray(rule.evidence)
      ? rule.evidence.map((item) => String(item).trim()).filter(Boolean).slice(0, 5)
      : [],
    confidence: Math.max(0, Math.min(1, Number(rule.confidence ?? 0.5)))
  }))
  .filter((rule) => rule.rule)
  .slice(0, 25);

return [{
  json: {
    memoryId: `memory:${original.articleId}:${Date.now()}`,
    feedbackId: original.feedbackId,
    articleId: original.articleId,
    writingMemory: {
      profileVersion: String(memory.profileVersion ?? '1.0.0'),
      rules,
      avoidPhrases: Array.isArray(memory.avoidPhrases)
        ? memory.avoidPhrases.map((item) => String(item).trim()).filter(Boolean).slice(0, 30)
        : [],
      preferredPatterns: Array.isArray(memory.preferredPatterns)
        ? memory.preferredPatterns.map((item) => String(item).trim()).filter(Boolean).slice(0, 30)
        : [],
      summary: String(memory.summary ?? '').trim()
    },
    sourceFeedback: {
      editorialDiff: original.editorialDiff,
      metrics: original.metrics
    },
    metadata: {
      workflow: '10-learning-agent',
      version: '1.0.0',
      provider: input.provider,
      status: 'memory_generated',
      generatedAt: new Date().toISOString()
    }
  }
}];
